 * LICENSE file in the root directory of this source tree.
 */

import {useState, useEffect} from 'react';

/**
 * Değişen bir değer için "debounced" (gecikmeli/biriktirilmiş) bir versiyon oluşturur.
 * `useDebounce` Hook'u, sağlanan değer (`value`) değiştiğinde, yeni değeri 
 * yalnızca belirtilen `delay` (gecikme) süresi boyunca başka bir değişiklik 
 * olmazsa döndürür.
 *
 * Bu Hook, bir kullanıcının yazmayı bitirmesini beklemek gibi durumlarda, 
 * maliyetli işlemleri (örneğin API çağrıları) sürekli tetiklememek için kullanışlıdır.
 *
 * @param {*} value "Debounce" uygulanacak değer. Herhangi bir tipte olabilir.
 * @param {number} delay Milisaniye cinsinden gecikme süresi.
 * @returns {*} Belirtilen gecikme süresi sonunda güncellenen "debounced" değer.
 *
 * @example
 * const [searchTerm, setSearchTerm] = useState('');
 * // Arama terimi 500ms boyunca değişmezse API çağrısı yapılır.
 * const debouncedSearchTerm = useDebounce(searchTerm, 500);
 * 
 * useEffect(() => {
 *   if (debouncedSearchTerm) {
 *     // API çağrısını burada yap
 *     fetch(`/api/search?q=${debouncedSearchTerm}`);
 *   }
 * }, [debouncedSearchTerm]); // Sadece debounced değer değiştiğinde çalışır
 */
function useDebounce(value, delay) {
  // "Debounced" değeri tutacak state
  const [debouncedValue, setDebouncedValue] = useState(value);

  useEffect(() => {
    // `value` veya `delay` değiştiğinde bir zamanlayıcı ayarla
    const handler = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    // Bu çok önemli: Eğer `value` veya `delay` tekrar değişirse
    // (yani `useEffect` yeniden çalışırsa), bir önceki zamanlayıcıyı temizle.
    // Bu sayede, kullanıcı yazmaya devam ederken zamanlayıcı sürekli sıfırlanır
    // ve fonksiyon gereksiz yere çalışmaz.
    return () => {
      clearTimeout(handler);
    };
  }, [value, delay]); // Sadece value veya delay değiştiğinde bu effect'i yeniden çalıştır

  return debouncedValue;
}

export default useDebounce;
```

### Kullanım Örneği (Bir Bileşen İçinde)

Bu Hook'un ne kadar pratik olduğunu göstermek için basit bir arama bileşeni oluşturalım.

```jsx
import React, { useState, useEffect } from 'react';
import useDebounce from './useDebounce'; // Yeni eklediğimiz Hook'u import ediyoruz

function SearchComponent() {
  // Kullanıcının anlık olarak girdiği değeri tutan state
  const [searchTerm, setSearchTerm] = useState('');

  // `searchTerm` için 500ms gecikmeli bir versiyon oluşturuyoruz
  const debouncedSearchTerm = useDebounce(searchTerm, 500);

  // Arama sonuçlarını tutacak state
  const [results, setResults] = useState([]);
  const [isSearching, setIsSearching] = useState(false);

  useEffect(() => {
    // Sadece `debouncedSearchTerm` değiştiğinde ve boş olmadığında API isteği yap
    if (debouncedSearchTerm) {
      setIsSearching(true);
      console.log(`API'ye istek gönderiliyor: ${debouncedSearchTerm}`);

      // Gerçek bir API isteğini simüle edelim
      fetch(`https://api.example.com/search?q=${debouncedSearchTerm}`)
        .then(response => response.json())
        .then(data => {
          setIsSearching(false);
          setResults(data.results || []);
        })
        .catch(error => {
            setIsSearching(false);
            console.error("Arama sırasında hata oluştu:", error);
        });
    } else {
      setResults([]);
    }
  }, [debouncedSearchTerm]); // <-- En önemli kısım: Bu effect sadece debounced değere bağlı

  return (
    <div>
      <h2>Arama Yap</h2>
      <input
        type="text"
        placeholder="Bir şeyler arayın..."
        value={searchTerm}
        onChange={(e) => setSearchTerm(e.target.value)}
        style={{ width: '300px', padding: '8px' }}
      />
      {isSearching && <div>Aranıyor...</div>}
      <ul>
        {results.map((result, index) => (
          <li key={index}>{result.title}</li>
        ))}
      </ul>
    </div>
  );
}

export default SearchComponent;
```

